var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"저도 한때 제 근본에 대해 생각해본 적은 있습니다.","JPN":"私とて、自らの根源について悩むことくらいありました。","ENG":"I once wondered who I was.","TWN":"我也曾經思考過我的存在。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"과거가 없는 한낱 복제품. 관리국을 위해 태어난 존재. 그게 고작 내 정체성의 전부일까......","JPN":"過去を持たない単なる複製品。管理局のために造り出された存在。果たしてそれが自分のアイデンティティのすべてなのかと……","ENG":"A clone with no past, purely born for the Administration. Was I really just that?","TWN":"一個沒有過去的克隆人，為了管理局而誕生的存在，這些就是我的一切嗎......"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이 따위 생각들은 부질없는 짓이었죠. 나 자신을 만드는 건 생각이 아닌 행동이었으니까요.","JPN":"しかし、それらの思考はすべて無意味でしかありませんでした。己を形作るのは、思考ではなく行動だとわかったのです。","ENG":"But I've decided thoughts like that are meaningless. I am who I am not because of what I think; because of what I do.","TWN":"但是這些想法毫無意義。創造我自己的，不是想法而是行動。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"적들을 쓰러트리고 고지를 정복할 때, 비로소 저는 살아있음을 느낍니다.","JPN":"敵を倒し、ポイントを占領したとき、私はようやく生きていることを実感できます。","ENG":"I feel alive when I defeat enemies and conquer the battlefield.","TWN":"當我打倒敵人，佔領高地的時候，我才終於感覺到我正活在世界上。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"까짓 남들 다 갖고 있는 추억쯤, 없으면 뭐 어떻습니까. 지금 내가 즐거우면 됐지.","JPN":"ありふれた思い出など、なくたって構わないのです。\\n今、私は楽しんでいる。それこそが大事なことです。","ENG":"What if I don't have good memories of my past? I'm happy now, and that's what matters.","TWN":"就算沒有別人擁有的回憶又如何？我只要當下過得開心就好了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"예? 추억쯤이야 앞으로 만들어나가면 되지 않느냐고요?","JPN":"はい？思い出なら、これから作って行けばいいと？","ENG":"Huh? I can create good memories from now on?","TWN":"嗯？你說回憶什麼的，以後再創造不就好了？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"크하하, 사장님. 보기와 다르게 꽤 로맨티스트셨군요.","JPN":"ハハ、社長。見かけによらずロマンチストなんですね。","ENG":"Hah hah. Boss, you're more romantic than you look.","TWN":"哈哈，老闆，看不出來您還是個浪漫主義者啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"기왕 추억을 만들어주실 거라면 제가 전력을 다할 수 있는 이벤트로 준비해주시죠.","JPN":"どうせ思い出を作るなら、私が全力を尽くせるようなイベントを用意していただきたいものです。","ENG":"If you want to help me create good memories, then find me an event that's challenging enough.","TWN":"既然您想要為我創造回憶，那就為我準備一場能夠傾盡全力的活動吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};